local GuiBuilder = {}
GuiBuilder.__index = GuiBuilder

function GuiBuilder.new(jsonChunks, targetPlayerGui, guiName)
	return setmetatable({
		JsonChunks = jsonChunks,
		PlayerGui = targetPlayerGui,
		GuiName = guiName,
	}, GuiBuilder)
end

function GuiBuilder:decodeEnumItem(info)
	local enumTypeName = tostring(info.EnumType)
	enumTypeName = enumTypeName:match("^Enum%.(.+)$") or enumTypeName

	local enumType = Enum[enumTypeName]
	if not enumType then
		return nil
	end

	return enumType[info.Name]
end

function GuiBuilder:decodeValue(v, idMap)
	if type(v) ~= "table" then
		return v
	end

	if v.__type == "ref" then
		return idMap[v.Id]
	elseif v.__type == "UDim2" then
		return UDim2.new(v.XScale, v.XOffset, v.YScale, v.YOffset)
	elseif v.__type == "UDim" then
		return UDim.new(v.Scale, v.Offset)
	elseif v.__type == "Vector2" then
		return Vector2.new(v.X, v.Y)
	elseif v.__type == "Vector3" then
		return Vector3.new(v.X, v.Y, v.Z)
	elseif v.__type == "Color3" then
		return Color3.new(v.R, v.G, v.B)
	elseif v.__type == "BrickColor" then
		return BrickColor.new(v.Name)
	elseif v.__type == "EnumItem" then
		return self:decodeEnumItem(v)
	elseif v.__type == "Font" then
		return Font.new(v.Family, Enum.FontWeight[v.Weight], Enum.FontStyle[v.Style])
	elseif v.__type == "Rect" then
		return Rect.new(self:decodeValue(v.Min, idMap), self:decodeValue(v.Max, idMap))
	elseif v.__type == "CFrame" then
		return CFrame.new(table.unpack(v.Components))
	elseif v.__type == "NumberRange" then
		return NumberRange.new(v.Min, v.Max)
	elseif v.__type == "ColorSequence" then
		local points = {}
		for _, kp in ipairs(v.Keypoints or {}) do
			table.insert(points, ColorSequenceKeypoint.new(kp.Time, self:decodeValue(kp.Value, idMap)))
		end
		return ColorSequence.new(points)
	elseif v.__type == "NumberSequence" then
		local points = {}
		for _, kp in ipairs(v.Keypoints or {}) do
			table.insert(points, NumberSequenceKeypoint.new(kp.Time, kp.Value, kp.Envelope or 0))
		end
		return NumberSequence.new(points)
	end

	return v
end

function GuiBuilder:createTree(node, parent, idMap)
	local inst = Instance.new(node.ClassName)
	idMap[node.Id] = inst
	inst.Name = node.Name
	inst.Parent = parent

	for _, child in ipairs(node.Children or {}) do
		self:createTree(child, inst, idMap)
	end

	return inst
end

function GuiBuilder:applyTree(node, idMap)
	local inst = idMap[node.Id]

	for k, v in pairs(node.Properties or {}) do
		pcall(function()
			inst[k] = self:decodeValue(v, idMap)
		end)
	end

	for k, v in pairs(node.Attributes or {}) do
		pcall(function()
			inst:SetAttribute(k, self:decodeValue(v, idMap))
		end)
	end

	for _, child in ipairs(node.Children or {}) do
		self:applyTree(child, idMap)
	end
end

function GuiBuilder:Build()
	local json = table.concat(self.JsonChunks)
	local data = HttpService:JSONDecode(json)

	local idMap = {}
	local root = self:createTree(data, nil, idMap)
	self:applyTree(data, idMap)

	root.Name = self.GuiName

	local existing = self.PlayerGui:FindFirstChild(self.GuiName)
	if existing then
		existing:Destroy()
	end

	root.Parent = self.PlayerGui
	return root
end




local ButtonHoverManager = {}
ButtonHoverManager.__index = ButtonHoverManager

function ButtonHoverManager.new(root, pattern, scale, tweenTime)
	return setmetatable({
		Root = root,
		Pattern = pattern,
		Scale = scale,
		TweenTime = tweenTime,
	}, ButtonHoverManager)
end

function ButtonHoverManager:BindButton(button)
	local originalSize = button.Size

	local hoverSize = UDim2.new(
		originalSize.X.Scale * self.Scale,
		originalSize.X.Offset * self.Scale,
		originalSize.Y.Scale * self.Scale,
		originalSize.Y.Offset * self.Scale
	)

	local tweenInfo = TweenInfo.new(self.TweenTime, Enum.EasingStyle.Quad, Enum.EasingDirection.Out)

	local growTween = TweenService:Create(button, tweenInfo, { Size = hoverSize })
	local shrinkTween = TweenService:Create(button, tweenInfo, { Size = originalSize })

	button.MouseEnter:Connect(function()
		growTween:Play()
	end)

	button.MouseLeave:Connect(function()
		shrinkTween:Play()
	end)
end

function ButtonHoverManager:BindAll()
	for _, obj in ipairs(self.Root:GetDescendants()) do
		if obj:IsA("GuiButton") and string.match(obj.Name, self.Pattern) then
			self:BindButton(obj)
		end
	end
end




local FrameHoverManager = {}
FrameHoverManager.__index = FrameHoverManager

function FrameHoverManager.new(frames, scale, tweenTime, darkenFactor)
	return setmetatable({
		Frames = frames,
		Scale = scale or 1.1,
		TweenTime = tweenTime or 0.15,
		DarkenFactor = darkenFactor or 0.8,
	}, FrameHoverManager)
end

function FrameHoverManager:BindFrame(frame)
	if not frame:IsA("GuiObject") then
		return
	end

	local originalColor = frame.BackgroundColor3

	local uiScale = frame:FindFirstChildOfClass("UIScale")
	if not uiScale then
		uiScale = Instance.new("UIScale")
		uiScale.Scale = 1
		uiScale.Parent = frame
	end

	local tweenInfo = TweenInfo.new(self.TweenTime, Enum.EasingStyle.Quad, Enum.EasingDirection.Out)

	local hoverColor = Color3.new(
		originalColor.R * self.DarkenFactor,
		originalColor.G * self.DarkenFactor,
		originalColor.B * self.DarkenFactor
	)

	local growTween = TweenService:Create(uiScale, tweenInfo, { Scale = self.Scale })
	local shrinkTween = TweenService:Create(uiScale, tweenInfo, { Scale = 1 })

	local darkenTween = TweenService:Create(frame, tweenInfo, { BackgroundColor3 = hoverColor })
	local lightenTween = TweenService:Create(frame, tweenInfo, { BackgroundColor3 = originalColor })

	frame.MouseEnter:Connect(function()
		growTween:Play()
		darkenTween:Play()
	end)

	frame.MouseLeave:Connect(function()
		shrinkTween:Play()
		lightenTween:Play()
	end)
end

function FrameHoverManager:BindAll()
	for _, frame in ipairs(self.Frames) do
		self:BindFrame(frame)
	end
end




local RainbowTextController = {}
RainbowTextController.__index = RainbowTextController

function RainbowTextController.new(textLabel, step, interval)
	return setmetatable({
		TextLabel = textLabel,
		Step = step,
		Interval = interval,
		Running = false,
	}, RainbowTextController)
end

function RainbowTextController:Start()
	local gradient = self.TextLabel:FindFirstChildOfClass("UIGradient")
	if not gradient then
		return
	end

	self.Running = true

	task.spawn(function()
		local hue = 0

		while self.Running do
			hue = (hue - self.Step) % 1

			gradient.Color = ColorSequence.new({
				ColorSequenceKeypoint.new(0.00, Color3.fromHSV((hue + 0.00) % 1, 1, 1)),
				ColorSequenceKeypoint.new(0.17, Color3.fromHSV((hue + 0.17) % 1, 1, 1)),
				ColorSequenceKeypoint.new(0.33, Color3.fromHSV((hue + 0.33) % 1, 1, 1)),
				ColorSequenceKeypoint.new(0.50, Color3.fromHSV((hue + 0.50) % 1, 1, 1)),
				ColorSequenceKeypoint.new(0.67, Color3.fromHSV((hue + 0.67) % 1, 1, 1)),
				ColorSequenceKeypoint.new(0.83, Color3.fromHSV((hue + 0.83) % 1, 1, 1)),
				ColorSequenceKeypoint.new(1.00, Color3.fromHSV((hue + 1.00) % 1, 1, 1)),
			})

			task.wait(self.Interval)
		end
	end)
end

function RainbowTextController:Stop()
	self.Running = false
end




local FrameToggleController = {}
FrameToggleController.__index = FrameToggleController

function FrameToggleController.new(frame, openPos, hiddenPos, tweenTime, cameraObj, blurSize, fovScale, visualTweenTime, otherGuiManager)
	local blur = Lighting:FindFirstChild("GuiBlur")
	if not blur then
		blur = Instance.new("BlurEffect")
		blur.Name = "GuiBlur"
		blur.Size = 0
		blur.Parent = Lighting
	end

	return setmetatable({
		Frame = frame,
		OpenPos = openPos,
		HiddenPos = hiddenPos,
		TweenTime = tweenTime,

		Camera = cameraObj,
		Blur = blur,

		OriginalFOV = cameraObj.FieldOfView,
		TargetFOV = cameraObj.FieldOfView * fovScale,

		BlurTarget = blurSize,
		VisualTweenTime = visualTweenTime,

		OtherGuiManager = otherGuiManager,

		IsOpen = false,
		Debounce = false,
	}, FrameToggleController)
end

function FrameToggleController:Init()
	self.Frame.AnchorPoint = Vector2.new(0.5, 0.5)
	self.Frame.Position = self.HiddenPos

	self.Blur.Size = 0
	self.Camera.FieldOfView = self.OriginalFOV
end

function FrameToggleController:PlayVisuals(open)
	local fovGoal = open and self.TargetFOV or self.OriginalFOV
	local blurGoal = open and self.BlurTarget or 0

	local fovTween = TweenService:Create(
		self.Camera,
		TweenInfo.new(self.VisualTweenTime, Enum.EasingStyle.Quad, Enum.EasingDirection.Out),
		{ FieldOfView = fovGoal }
	)

	local blurTween = TweenService:Create(
		self.Blur,
		TweenInfo.new(self.VisualTweenTime, Enum.EasingStyle.Quad, Enum.EasingDirection.Out),
		{ Size = blurGoal }
	)

	fovTween:Play()
	blurTween:Play()
end

function FrameToggleController:SetOpen(state)
	if self.Debounce then
		return
	end
	if self.OtherGuiManager then
		if state then
			self.OtherGuiManager:SlideOut()
		else
			self.OtherGuiManager:SlideIn()
		end
	end
	self.Debounce = true
	self.IsOpen = state

	self:PlayVisuals(state)

	local frameTween = TweenService:Create(
		self.Frame,
		TweenInfo.new(self.TweenTime, Enum.EasingStyle.Quad, Enum.EasingDirection.Out),
		{
			Position = state and self.OpenPos or self.HiddenPos
		}
	)

	frameTween:Play()
	frameTween.Completed:Wait()

	self.Debounce = false
end

function FrameToggleController:Toggle()
	self:SetOpen(not self.IsOpen)
end

function FrameToggleController:BindKey(keyCode)
	UserInputService.InputBegan:Connect(function(input, gameProcessed)
		if gameProcessed then
			return
		end

		if input.KeyCode == keyCode then
			self:Toggle()
		end
	end)
end



