local function AddRound(parent, radius)
	local c = Instance.new("UICorner")
	c.CornerRadius = UDim.new(0, radius)
	c.Parent = parent
	return c
end

local function AddStroke(parent, color, transparency, thickness)
	local s = Instance.new("UIStroke")
	s.Color = color
	s.Transparency = transparency or 0
	s.Thickness = thickness or 1
	s.Parent = parent
	return s
end

local function AddPadding(parent, left, right, top, bottom)
	local p = Instance.new("UIPadding")
	p.PaddingLeft = UDim.new(0, left or 0)
	p.PaddingRight = UDim.new(0, right or 0)
	p.PaddingTop = UDim.new(0, top or 0)
	p.PaddingBottom = UDim.new(0, bottom or 0)
	p.Parent = parent
	return p
end

local original = {}

local function CacheOriginals(root)
	local function save(obj)
		original[obj] = {
			BG = obj:IsA("GuiObject") and obj.BackgroundTransparency or nil,
			Text = (obj:IsA("TextLabel") or obj:IsA("TextButton")) and obj.TextTransparency or nil,
			Image = (obj:IsA("ImageLabel") or obj:IsA("ImageButton")) and obj.ImageTransparency or nil
		}
	end

	save(root)

	for _, v in ipairs(root:GetDescendants()) do
		save(v)
	end
end
local OriginalState = {}
local function SaveOriginals(frame)
	if OriginalState[frame] then return end

	local data = {}


	data[frame] = {
		Position = frame.Position,
		Size = frame.Size,
		AnchorPoint = frame.AnchorPoint,
		BackgroundTransparency = frame.BackgroundTransparency,
		Visible = frame.Visible
	}


	for _, v in ipairs(frame:GetDescendants()) do
		if v:IsA("TextLabel") or v:IsA("TextButton") then
			data[v] = {
				TextTransparency = v.TextTransparency,
				BackgroundTransparency = v.BackgroundTransparency
			}
		elseif v:IsA("Frame") then
			data[v] = {
				BackgroundTransparency = v.BackgroundTransparency
			}
		end
	end

	OriginalState[frame] = data
end
local function Restore(frame)
	local data = OriginalState[frame]
	if not data then return end

	for obj, props in pairs(data) do
		if obj and obj.Parent then
			for k, v in pairs(props) do
				obj[k] = v
			end
		end
	end
end
local function RestoreOriginals()
	for obj, data in pairs(original) do
		if obj and obj.Parent then
			if data.BG ~= nil then
				obj.BackgroundTransparency = data.BG
			end
			if data.Text ~= nil then
				obj.TextTransparency = data.Text
			end
			if data.Image ~= nil then
				obj.ImageTransparency = data.Image
			end
		end
	end
end
local function ParseNumber(str)

	str = string.gsub(str, "%D", "")
	return tonumber(str) or 0
end

local function FormatNumber(num)
	local str = tostring(math.floor(num))
	while true do
		str, k = string.gsub(str, "^(-?%d+)(%d%d%d)", "%1,%2")
		if k == 0 then break end
	end
	return str
end
local function PlayShopUI(RobuxFrame, NextFrame, OverlayFrame)
	local TweenService = game:GetService("TweenService")

	local Count = RobuxFrame:WaitForChild("Count")
	local NextCount = NextFrame:WaitForChild("Count")
	local BuyBar = RobuxFrame:WaitForChild("BuyBar")
	local Fill = BuyBar:WaitForChild("BuyBar2")
	local Close = RobuxFrame:WaitForChild("Close")

	local canClick = false
	local isProcessing = false




	local ORIGINAL_FILL_COLOR = Fill.BackgroundColor3
	local HOVER_BRIGHTNESS = 1.15

	local function TweenFillColor(targetColor, duration)
		TweenService:Create(Fill, TweenInfo.new(duration or 0.15, Enum.EasingStyle.Quad), {
			BackgroundColor3 = targetColor
		}):Play()
	end

	BuyBar.MouseEnter:Connect(function()
		if isProcessing then return end
		local hoverColor = Color3.new(
			math.min(1, ORIGINAL_FILL_COLOR.R * HOVER_BRIGHTNESS),
			math.min(1, ORIGINAL_FILL_COLOR.G * HOVER_BRIGHTNESS),
			math.min(1, ORIGINAL_FILL_COLOR.B * HOVER_BRIGHTNESS)
		)
		TweenFillColor(hoverColor)
	end)

	BuyBar.MouseLeave:Connect(function()
		if isProcessing then return end
		TweenFillColor(ORIGINAL_FILL_COLOR)
	end)




	isProcessing = false
	canClick = false
	Fill.Size = UDim2.new(0, 0, 1, 0)
	Fill.Visible = true
	Fill.BackgroundColor3 = ORIGINAL_FILL_COLOR

	RestoreOriginals()
	Restore(NextFrame)

	RobuxFrame.Visible = true
	RobuxFrame.AnchorPoint = Vector2.new(0.5, 0.5)
	RobuxFrame.Position = UDim2.new(0.5, 0, 0.55, 40)
	RobuxFrame.BackgroundTransparency = 0




	if OverlayFrame then
		OverlayFrame.Visible = true
		OverlayFrame.BackgroundTransparency = 1
		TweenService:Create(OverlayFrame, TweenInfo.new(0.35, Enum.EasingStyle.Quad), {
			BackgroundTransparency = 0.25
		}):Play()
	end

	TweenService:Create(RobuxFrame, TweenInfo.new(0.35, Enum.EasingStyle.Quad), {
		Position = UDim2.new(0.5, 0, 0.5, 0)
	}):Play()




	local fillTween = TweenService:Create(Fill, TweenInfo.new(1.6, Enum.EasingStyle.Quint, Enum.EasingDirection.In), {
		Size = UDim2.new(1, 0, 1, 0)
	})
	fillTween:Play()
	fillTween.Completed:Connect(function()
		canClick = true
	end)





	local function CloseUI(frame, onDone, fadeOverlay)
		if fadeOverlay == nil then fadeOverlay = true end  

		if frame:GetAttribute("Busy") then return end
		frame:SetAttribute("Busy", true)


		if fadeOverlay and OverlayFrame then
			TweenService:Create(OverlayFrame, TweenInfo.new(0.35, Enum.EasingStyle.Quad), {
				BackgroundTransparency = 1
			}):Play()
		end

		local hideTween = TweenService:Create(frame, TweenInfo.new(0.25, Enum.EasingStyle.Quad, Enum.EasingDirection.In), {
			Position = UDim2.new(0.5, 0, 0.6, 40),
			BackgroundTransparency = 1
		})

		for _, v in ipairs(frame:GetDescendants()) do
			if v:IsA("TextLabel") or v:IsA("TextButton") then
				TweenService:Create(v, TweenInfo.new(0.2), {
					TextTransparency = 1,
					BackgroundTransparency = 1
				}):Play()
			elseif v:IsA("Frame") then
				TweenService:Create(v, TweenInfo.new(0.2), {
					BackgroundTransparency = 1
				}):Play()
			end
		end

		hideTween:Play()
		hideTween.Completed:Connect(function()
			frame.Visible = false
			frame:SetAttribute("Busy", false)
			if onDone then onDone() end
		end)
	end




	Close.Active = true
	Close.InputBegan:Connect(function(input)
		if input.UserInputType ~= Enum.UserInputType.MouseButton1 then return end

		CloseUI(RobuxFrame)
	end)




	BuyBar.Active = true
	BuyBar.InputBegan:Connect(function(input)
		if input.UserInputType ~= Enum.UserInputType.MouseButton1 then return end
		if not canClick or isProcessing then return end

		isProcessing = true
		canClick = false
		Fill.Visible = false
		TweenFillColor(ORIGINAL_FILL_COLOR, 0)


		local prefix = Count.Text:match("^[^%d]*") or ""
		local current = tonumber((Count.Text:gsub("%D", ""))) or 0
		current = math.max(0, current - 11000)
		local newText = prefix .. FormatNumber(current)

		Count.Text = newText
		NextCount.Text = newText


		task.delay(0.65, function()

			CloseUI(RobuxFrame, function()
				local nextClose = NextFrame:WaitForChild("Close")
				local okBtn = NextFrame:WaitForChild("Ok")

				NextFrame.Visible = true
				NextFrame.AnchorPoint = Vector2.new(0.5, 0.5)
				NextFrame.Position = UDim2.new(0.5, 0, 0.55, 40)

				TweenService:Create(NextFrame, TweenInfo.new(0.35, Enum.EasingStyle.Quad), {
					Position = UDim2.new(0.5, 0, 0.5, 0)
				}):Play()




				local function HandleNextClose()
					if NextFrame:GetAttribute("Busy") then return end


					if OverlayFrame then
						TweenService:Create(OverlayFrame, TweenInfo.new(0.35, Enum.EasingStyle.Quad), {
							BackgroundTransparency = 1
						}):Play()
					end

					local hideTween = TweenService:Create(NextFrame, TweenInfo.new(0.25, Enum.EasingStyle.Quad, Enum.EasingDirection.In), {
						Position = UDim2.new(0.5, 0, 0.6, 40),
						BackgroundTransparency = 1
					})

					for _, v in ipairs(NextFrame:GetDescendants()) do
						if v:IsA("TextLabel") or v:IsA("TextButton") then
							TweenService:Create(v, TweenInfo.new(0.2), {
								TextTransparency = 1,
								BackgroundTransparency = 1
							}):Play()
						elseif v:IsA("Frame") then
							TweenService:Create(v, TweenInfo.new(0.2), {
								BackgroundTransparency = 1
							}):Play()
						end
					end

					hideTween:Play()
					hideTween.Completed:Connect(function()
						NextFrame.Visible = false
						NextFrame:SetAttribute("Busy", false)
					end)
				end

				nextClose.Active = true
				nextClose.InputBegan:Connect(function(input2)
					if input2.UserInputType == Enum.UserInputType.MouseButton1 or input2.UserInputType == Enum.UserInputType.Touch then
						HandleNextClose()
					end
				end)

				okBtn.Active = true
				okBtn.InputBegan:Connect(function(input2)
					if input2.UserInputType == Enum.UserInputType.MouseButton1 or input2.UserInputType == Enum.UserInputType.Touch then
						HandleNextClose()
					end
				end)
			end, false)  
		end)
	end)
end



