local function FindPlayerByQuery(query)
	query = trim(query)
	if query == "" then return nil end

	local userId = tonumber(query)
	if userId and userId > 0 then
		local success, username = pcall(Players.GetNameFromUserIdAsync, Players, userId)
		if success and username then
			return { Name = username, UserId = userId }
		end
	end

	local success, foundUserId = pcall(Players.GetUserIdFromNameAsync, Players, query)
	if success and foundUserId then
		return { Name = query, UserId = foundUserId }
	end
	return nil
end


local function BuildGlobalList(query)
	for _, child in ipairs(scrollGlobal:GetChildren()) do
		if child:IsA("GuiObject") and child.Name ~= templateGlobal.Name then
			child:Destroy()
		end
	end

	query = trim(query)
	if query == "" then
		templateGlobal.Visible = false
		return
	end

	local playerData = FindPlayerByQuery(query)
	if not playerData then
		templateGlobal.Visible = false
		return
	end

	local clone = templateGlobal:Clone()
	clone.Name = "GlobalItem_" .. playerData.UserId
	clone.Visible = true

	local nickLbl = clone:FindFirstChild("NickName")
	if nickLbl and nickLbl:IsA("TextLabel") then
		nickLbl.Text = playerData.Name
	end
	local avatarImg = clone:FindFirstChild("Avatar")
	if avatarImg and avatarImg:IsA("ImageLabel") then
		avatarImg.Image = GetAvatar(playerData.UserId)
	end

	local giftFrame = clone:FindFirstChild("Gift")
	if giftFrame then
		local selectBtn = giftFrame:FindFirstChildOfClass("TextButton")
		if selectBtn then
			selectBtn.MouseButton1Click:Connect(function()
				selectedPlayer = { Name = playerData.Name, UserId = playerData.UserId }
				playerNameLbl.Text = playerData.Name
				playerImgLbl.Image = GetAvatar(playerData.UserId)
				playerSelectedFrame.Visible = true
			end)
		end
	end
	clone.Parent = scrollGlobal
end


local function BuildServerList()
	for _, child in ipairs(scrollFrame:GetChildren()) do
		if child:IsA("GuiObject") and child.Name ~= template.Name then
			child:Destroy()
		end
	end

	local allPlayers = Players:GetPlayers()
	table.sort(allPlayers, function(a, b) return a.Name:lower() < b.Name:lower() end)

	for _, plr in ipairs(allPlayers) do
		local clone = template:Clone()
		clone.Name = "PlayerItem_" .. plr.UserId
		clone.Visible = true

		local nickLbl = clone:FindFirstChild("NickName")
		if nickLbl and nickLbl:IsA("TextLabel") then
			nickLbl.Text = plr.Name
		end
		local avatarImg = clone:FindFirstChild("Avatar")
		if avatarImg and avatarImg:IsA("ImageLabel") then
			avatarImg.Image = GetAvatar(plr.UserId)
		end

		local giftFrame = clone:FindFirstChild("Gift")
		if giftFrame then
			local selectBtn = giftFrame:FindFirstChildOfClass("TextButton")
			if selectBtn then
				selectBtn.MouseButton1Click:Connect(function()
					selectedPlayer = plr
					playerNameLbl.Text = plr.Name
					playerImgLbl.Image = GetAvatar(plr.UserId)
					playerSelectedFrame.Visible = true
				end)
			end
		end
		clone.Parent = scrollFrame
	end
end


local function ToggleGiftList()
	if not isListOpen then

		isListOpen = true
		txtLabel.Text = "Back"
		giftGui.Visible = true
		playerSelectedFrame.Visible = false  


		if currentMode == "Server" then
			BuildServerList()
		else
			BuildGlobalList(searchBox.Text)
		end
	else

		isListOpen = false
		txtLabel.Text = originalText
		giftGui.Visible = false
		selectedPlayer = nil
		playerSelectedFrame.Visible = false
		searchBox:ReleaseFocus()
	end
end


buyBtn.MouseButton1Click:Connect(ToggleGiftList)


closeBtn.MouseButton1Click:Connect(function()

	giftGui.Visible = false
	searchBox:ReleaseFocus()


end)


local serverBtn = serverBtnFrame:FindFirstChildWhichIsA("TextButton") or serverBtnFrame
serverBtn.MouseButton1Click:Connect(function()
	UpdateButtonStates("Server")
	searchBox:ReleaseFocus()
	if isListOpen then BuildServerList() end
end)


local globalBtn = globalBtnFrame:FindFirstChildWhichIsA("TextButton") or globalBtnFrame
globalBtn.MouseButton1Click:Connect(function()
	UpdateButtonStates("Global")
	if isListOpen then
		searchBox:CaptureFocus()
		BuildGlobalList(searchBox.Text)
	end
end)


searchBox.FocusLost:Connect(function(enterPressed)
	if not enterPressed or searchDebounce then return end
	if currentMode ~= "Global" then return end

	searchDebounce = true
	task.delay(1, function() searchDebounce = false end)
	BuildGlobalList(searchBox.Text)
end)


