local function SetRobuxText(price, title, price10k, price11k, rub, hideIcon)
	local priceLabel = robuxFrame:WaitForChild("price")
	local icon = priceLabel.Text:match("^[^%d]*") or ""

	priceLabel.Text = icon .. tostring(price)
	priceLabel:WaitForChild("10k").Text = title

	local priceFrame = robuxFrame:WaitForChild("Frame")
	priceFrame:WaitForChild("10k").Text = icon .. tostring(price10k)
	priceFrame:WaitForChild("11k").Text = icon .. tostring(price11k)
	priceFrame:WaitForChild("rub").Text = rub

	local iconImage = robuxFrame:WaitForChild("icon"):WaitForChild("ImageLabel")
	iconImage.BackgroundColor3 = Color3.fromRGB(25, 26, 31)

	if hideIcon then
		iconImage.Image = ""
	else
		iconImage.Image = originalIconImage
	end

	local confirmTitle = robuxConfirm:WaitForChild("Title2")
	confirmTitle.Text = 'You have successfully bought "' .. title .. '".'
end

local function OpenShop(price, title, price10k, price11k, rub, hideIcon)
	SetRobuxText(price, title, price10k, price11k, rub, hideIcon)

	PlayShopUI(
		robuxFrame,
		robuxConfirm,
		root:WaitForChild("Frame")
	)
end

